#include <bits/stdc++.h>
using namespace std;

int p,q,af,as,n,m;
int ans[2][2],base[2][2],tmp[2][2];

int main(){
    scanf("%d%d%d%d%d%d",&p,&q,&af,&as,&n,&m);
    ans[0][0]=ans[1][1]=1;
    base[1][0]=1,base[0][1]=q%m,base[1][1]=p%m;
    if(n==1){
        printf("%d",af%m);
        return 0;
    }
    n-=2;
    while(n){
        if(n&1){
            for(int i=0;i<2;i++)
                for(int j=0;j<2;j++)
                    tmp[i][j]=(1ll*ans[i][0]*base[0][j]+1ll*ans[i][1]*base[1][j])%m;
            for(int i=0;i<2;i++)
                for(int j=0;j<2;j++)
                    ans[i][j]=tmp[i][j];
        }
        for(int i=0;i<2;i++)
            for(int j=0;j<2;j++)
                tmp[i][j]=(1ll*base[i][0]*base[0][j]+1ll*base[i][1]*base[1][j])%m;
        for(int i=0;i<2;i++)
            for(int j=0;j<2;j++)
                base[i][j]=tmp[i][j];
        n>>=1;
    }
    printf("%d",(1ll*af*ans[0][1]+1ll*as*ans[1][1])%m);
    return 0;
}
